 62â†’    @Test
 63â†’    void testFreezeStrategySetsVelocityToZero() {
 64â†’        Ball source = makeBall(new Point(100, 100), new Point(5, 3), Color.RED, 10);
 65â†’        Ball target = makeBall(new Point(115, 100), new Point(-3, 2), Color.BLUE, 10);
 66â†’        FreezeStrategy freeze = new FreezeStrategy();
 67â†’        IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
 68â†’
