 16â†’
 17â†’	@Override
 18â†’	public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
 19â†’		double distance = source.getLocation().distance(target.getLocation());
 20â†’		double minSeparation = source.getRadius() + target.getRadius();
 21â†’
 22â†’		if (distance < minSeparation && distance > 0) {
 23â†’			Point2D.Double unitVec = calcUnitVec(source.getLocation(), target.getLocation(), distance);
 24â†’			double mSource = source.getRadius() * (double) source.getRadius();
 25â†’			double mTarget = target.getRadius() * (double) target.getRadius();
 26â†’			double rm = reducedMass(mSource, mTarget);
 27â†’			Point2D.Double impulseVec = impulse(unitVec, source.getVelocity(), target.getVelocity(), rm);
 28â†’
 29â†’			updateVelocity(source, mSource, impulseVec);
 30â†’			updateVelocity(target, mTarget, new Point2D.Double(-impulseVec.x, -impulseVec.y));
 31â†’
 32â†’			Point nudge = calcNudgeVec(unitVec, minSeparation, distance);
 33â†’			source.setLocation(new Point(source.getLocation().x + nudge.x, source.getLocation().y + nudge.y));
 34â†’			target.setLocation(new Point(target.getLocation().x - nudge.x, target.getLocation().y - nudge.y));
 35â†’		}
 36â†’
 37â†’		return (context, d) -> {};
 38â†’	}
 39â†’
 40â†’	/**
 41â†’	 * Returns the reduced mass of the two balls (m1*m2)/(m1+m2) Gives correct
 42â†’	 * result if one of the balls has infinite mass.
 43â†’	 *
 44â†’	 * @param mSource
 45â†’	 *            Mass of the source ball
 46â†’	 * @param mTarget
 47â†’	 *            Mass of the target ball
 48â†’	 * @return The reduced mass of the two balls
 49â†’	 */
 50â†’	protected double reducedMass(double mSource, double mTarget) {
 51â†’		return (mSource * mTarget) / (mSource + mTarget);
 52â†’	}
 53â†’
 54â†’	/**
 55â†’	 * Calculate the unit vector (normalized vector) from the location of the source ball to the location of the target ball.
 56â†’	 * @param lSource Location of the source ball
 57â†’	 * @param lTarget Location of the target ball
 58â†’	 * @param distance Distance from the source ball to the target ball
 59â†’	 * @return A double-precision vector (point)
 60â†’	 */
 61â†’	Point2D.Double calcUnitVec(Point lSource, Point lTarget, double distance) {
 62â†’		double dx = lTarget.x - lSource.x;
 63â†’		double dy = lTarget.y - lSource.y;
 64â†’		return new Point2D.Double(dx / distance, dy / distance);
 65â†’	}
