 85â†’	protected Point2D.Double impulse(Point2D.Double normalVec, Point vSource, Point vTarget, double reducedMass) {
 86â†’		double relVelN = (vTarget.x - vSource.x) * normalVec.x + (vTarget.y - vSource.y) * normalVec.y;
 87â†’		double impulseMag = 2.0 * reducedMass * relVelN;
 88â†’		return new Point2D.Double(impulseMag * normalVec.x, impulseMag * normalVec.y);
